// src/pages/LeaveRequests.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function LeaveRequests() {
  const { leaveRequests, updateLeaveStatus, acceptSubstitute, currentUser } = useApp();
  const [filter, setFilter] = useState('all');
  const [expanded, setExpanded] = useState(null);

  const isAdmin = currentUser.role === 'admin';

  // Filter logic for staff: show only relevant substitute requests
  const filtered = leaveRequests
    .filter(req => {
      if (isAdmin) return filter === 'all' ? true : req.status === filter;

      // Staff view: show requests where they are in freeTeachers OR they are the submitter
      const relevantSubs = req.substituteRequests.some(sub =>
        sub.freeTeachers.some(t => t.id === currentUser.id)
      );
      const isSubmitter = req.teacherId === currentUser.id;
      if (!relevantSubs && !isSubmitter) return false;
      return filter === 'all' ? true : req.status === filter;
    })
    .sort((a, b) => b.id - a.id);

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📋 Leave Requests</h1>

      {/* Filter Tabs */}
      <div style={styles.tabs}>
        {['all', 'pending', 'approved', 'rejected'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{ ...styles.tab, ...(filter === f ? styles.tabActive : {}) }}
          >
            {f === 'all' ? '📋 All' : f === 'pending' ? '⏳ Pending' : f === 'approved' ? '✅ Approved' : '❌ Rejected'}
          </button>
        ))}
      </div>

      <div style={styles.list}>
        {filtered.length === 0 && <div style={styles.empty}>No leave requests found</div>}
        {filtered.map(req => (
          <div key={req.id} style={styles.card}>
            <div style={styles.cardHeader}>
              <div style={styles.leftInfo}>
                <div style={styles.avatar}>{req.teacherName[0]}</div>
                <div>
                  <div style={styles.teacherName}>{req.teacherName}</div>
                  <div style={styles.dates}>📅 {req.fromDate} → {req.toDate}</div>
                  <div style={styles.reason}>📝 {req.reason}</div>
                  <div style={styles.meta}>
                    Applied: {req.createdAt} | {req.substituteRequests.length} class(es) affected
                  </div>
                </div>
              </div>

              <div style={styles.rightActions}>
                <StatusBadge status={req.status} />

                {/* Admin buttons */}
                {isAdmin && req.status === 'pending' && (
                  <div style={styles.actionBtns}>
                    <button style={styles.approveBtn} onClick={() => updateLeaveStatus(req.id, 'approved')}>✅ Approve</button>
                    <button style={styles.rejectBtn} onClick={() => updateLeaveStatus(req.id, 'rejected')}>❌ Reject</button>
                  </div>
                )}
              </div>
            </div>

            {/* Substitute Section */}
            {req.substituteRequests.length > 0 && (
              <div style={styles.subSection}>
                <h3 style={styles.subTitle}>🔄 Substitute Assignments</h3>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      {['Date', 'Day', 'Period', 'Time', 'Class', 'Substitute Teacher'].map(h => (
                        <th key={h} style={styles.th}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {req.substituteRequests.map((sub, idx) => {
                      const isAssigned = sub.assignedTeacherId;
                      const isCurrentTeacherFree = sub.freeTeachers.some(t => t.id === currentUser.id);
                      const isSubmitter = req.teacherId === currentUser.id;

                      return (
                        <tr key={idx} style={styles.tr}>
                          <td style={styles.td}>{sub.date}</td>
                          <td style={styles.td}>{sub.day}</td>
                          <td style={styles.td}><span style={styles.periodBadge}>P{sub.period}</span></td>
                          <td style={styles.td}>{sub.time}</td>
                          <td style={styles.td}><strong>{sub.class}</strong></td>
                          <td style={styles.td}>
                            {isAssigned ? (
                              <span style={styles.assigned}>
                                ✔ Assigned to {sub.freeTeachers.concat({id: req.teacherId, name: req.teacherName}).find(t => t.id === isAssigned)?.name}
                                {isSubmitter && <span> (Accepted)</span>}
                              </span>
                            ) : isCurrentTeacherFree ? (
                              <button
                                style={styles.acceptBtn}
                                onClick={() => acceptSubstitute(req.id, idx, currentUser.id)}
                              >
                                Accept
                              </button>
                            ) : (
                              <span style={styles.waiting}>Waiting for teacher</span>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

function StatusBadge({ status }) {
  const map = {
    pending: { bg: '#fef3c7', color: '#92400e', label: '⏳ Pending' },
    approved: { bg: '#d1fae5', color: '#065f46', label: '✅ Approved' },
    rejected: { bg: '#fee2e2', color: '#991b1b', label: '❌ Rejected' },
  };
  const s = map[status] || map.pending;
  return (
    <span style={{ background: s.bg, color: s.color, padding: '6px 16px', borderRadius: 20, fontSize: 13, fontWeight: 700 }}>
      {s.label}
    </span>
  );
}
